trait Compressor {
    fn compress(&self, data: &[u8]) -> Vec<u8>;
    fn name(&self) -> &str;
}

struct NoCompression;
impl Compressor for NoCompression {
    fn compress(&self, data: &[u8]) -> Vec<u8> {
        data.to_vec()
    }
    fn name(&self) -> &str { "none" }
}

struct RunLengthEncoding;
impl Compressor for RunLengthEncoding {
    fn compress(&self, data: &[u8]) -> Vec<u8> {
        let mut result = Vec::new();
        let mut i = 0;
        while i < data.len() {
            let byte = data[i];
            let mut count: u8 = 1;
            while i + (count as usize) < data.len()
                && data[i + count as usize] == byte
                && count < 255
            {
                count += 1;
            }
            result.push(count);
            result.push(byte);
            i += count as usize;
        }
        result
    }
    fn name(&self) -> &str { "RLE" }
}

// Static dispatch (generics) -- zero cost, monomorphized
fn save_with_compression<C: Compressor>(data: &[u8], compressor: &C) {
    let compressed = compressor.compress(data);
    println!("[{}] {} bytes -> {} bytes",
        compressor.name(), data.len(), compressed.len());
}

// Dynamic dispatch (trait objects) -- flexible, runtime selection
fn get_compressor(name: &str) -> Box<dyn Compressor> {
    match name {
        "rle" => Box::new(RunLengthEncoding),
        _ => Box::new(NoCompression),
    }
}

fn main() {
    let data = b"AAABBBCCCCDDDD";

    // Static dispatch
    save_with_compression(data, &RunLengthEncoding);
    save_with_compression(data, &NoCompression);

    // Dynamic dispatch
    let compressor = get_compressor("rle");
    save_with_compression(data, compressor.as_ref());
}
